class ScienceSimulation {
    constructor(container, initialInputs) {
        this.container = container;
        this.canvas = document.createElement('canvas');
        this.ctx = this.canvas.getContext('2d');
        this.container.appendChild(this.canvas);
        this.resize();
        window.addEventListener('resize', () => this.resize());

        // Fixed Initial weights for the 'Solved Example' logic
        this.weights = {
            w11: 0.15, w21: 0.20, b1: 0.35,
            w12: 0.25, w22: 0.30,
            v1: 0.40, v2: 0.45, b2: 0.60
        };
    }

    resize() {
        this.canvas.width = this.container.clientWidth;
        this.canvas.height = this.container.clientHeight || 500;
    }

    sigmoid(z) { return 1 / (1 + Math.exp(-z)); }
    sigmoidDeriv(a) { return a * (1 - a); }

    calculate(inputs) {
        const { x1, x2, target } = inputs;
        const { w11, w21, b1, w12, w22, v1, v2, b2 } = this.weights;

        // Hidden Layer
        const zh1 = x1 * w11 + x2 * w21 + b1;
        const h1 = this.sigmoid(zh1);
        const zh2 = x1 * w12 + x2 * w22 + b1;
        const h2 = this.sigmoid(zh2);

        // Output Layer
        const zo = h1 * v1 + h2 * v2 + b2;
        const out = this.sigmoid(zo);

        // Error
        const error = 0.5 * Math.pow(target - out, 2);

        // Backprop - Output Layer
        const dE_dout = -(target - out);
        const dout_dzo = this.sigmoidDeriv(out);
        const dE_dzo = dE_dout * dout_dzo;

        const dE_dv1 = dE_dzo * h1;
        const dE_dv2 = dE_dzo * h2;
        const dE_db2 = dE_dzo;

        // Backprop - Hidden Layer
        const dE_dh1 = dE_dzo * v1;
        const dh1_dzh1 = this.sigmoidDeriv(h1);
        const dE_dw11 = dE_dh1 * dh1_dzh1 * x1;
        const dE_dw21 = dE_dh1 * dh1_dzh1 * x2;

        return { zh1, h1, zh2, h2, zo, out, error, dE_dzo, dE_dv1, dE_dv2, dE_dw11, dE_dw21 };
    }

    getSteps(inputs) {
        const calc = this.calculate(inputs);
        return [
            {
                title: "Step 1: Network Architecture",
                description: "We have a simple 2-2-1 MLP. Inputs: $x_1=" + inputs.x1 + "$, $x_2=" + inputs.x2 + "$. Target: $y=" + inputs.target + "$. Weights are initialized to small values."
            },
            {
                title: "Step 2: Forward Pass (Hidden Layer)",
                description: "Calculate hidden neuron $h_1$ value:\\n $z_{h1} = (w_{11}x_1 + w_{21}x_2 + b_1) = " + calc.zh1.toFixed(3) + "$\\n $a_{h1} = \\sigma(z_{h1}) = " + calc.h1.toFixed(3) + "$. Same for $h_2$."
            },
            {
                title: "Step 3: Forward Pass (Output Layer)",
                description: "Calculate final output:\\n $z_{o} = (v_1h_1 + v_2h_2 + b_2) = " + calc.zo.toFixed(3) + "$\\n $Output = \\sigma(z_{o}) = " + calc.out.toFixed(3) + "$."
            },
            {
                title: "Step 4: Error Calculation",
                description: "Using Mean Squared Error:\\n $E = \\frac{1}{2}(target - output)^2 = " + calc.error.toFixed(5) + "$. This is what we want to minimize."
            },
            {
                title: "Step 5: Backprop (Output Gradients)",
                description: "Using chain rule, find gradient for weight $v_1$:\\n $\\frac{\\partial E}{\\partial v_1} = (out - target) \\cdot out(1-out) \\cdot h_1 = " + calc.dE_dv1.toFixed(4) + "$."
            },
            {
                title: "Step 6: Backprop (Hidden Gradients)",
                description: "Propagate error back to hidden weights:\\n $\\frac{\\partial E}{\\partial w_{11}} = \\frac{\\partial E}{\\partial h_1} \\cdot \\frac{\\partial h_1}{\\partial z_{h1}} \\cdot x_1 = " + calc.dE_dw11.toFixed(4) + "$."
            },
            {
                title: "Step 7: Weight Update",
                description: "Update weights using learning rate $\\eta = " + inputs.lr + "$:\\n $w_{new} = w_{old} - \\eta \\cdot \\frac{\\partial E}{\\partial w}$."
            }
        ];
    }

    render(inputs, stepIndex) {
        const { ctx, canvas } = this;
        const calc = this.calculate(inputs);
        ctx.clearRect(0, 0, canvas.width, canvas.height);

        const nodeRadius = 25;
        const xPos = [canvas.width * 0.2, canvas.width * 0.5, canvas.width * 0.8];
        const yPosIn = [canvas.height * 0.35, canvas.height * 0.65];
        const yPosHid = [canvas.height * 0.35, canvas.height * 0.65];
        const yPosOut = [canvas.height * 0.5];

        // Draw Connections
        const drawEdge = (x1, y1, x2, y2, color, weightVal, isActive) => {
            ctx.beginPath();
            ctx.moveTo(x1, y1);
            ctx.lineTo(x2, y2);
            ctx.strokeStyle = isActive ? '#3b82f6' : '#cbd5e1';
            ctx.lineWidth = isActive ? 4 : 1.5;
            ctx.stroke();

            if (isActive) {
                ctx.fillStyle = '#1e293b';
                ctx.font = 'bold 12px Arial';
                ctx.fillText(weightVal, (x1 + x2) / 2, (y1 + y2) / 2 - 5);
            }
        };

        // Step logic for highlighting
        const showInToHid = stepIndex >= 1;
        const showHidToOut = stepIndex >= 2;
        const showBackOut = stepIndex >= 4;
        const showBackHid = stepIndex >= 5;

        // Edges: Input to Hidden
        drawEdge(xPos[0], yPosIn[0], xPos[1], yPosHid[0], '', this.weights.w11, showInToHid);
        drawEdge(xPos[0], yPosIn[1], xPos[1], yPosHid[0], '', this.weights.w21, showInToHid);
        drawEdge(xPos[0], yPosIn[0], xPos[1], yPosHid[1], '', this.weights.w12, showInToHid);
        drawEdge(xPos[0], yPosIn[1], xPos[1], yPosHid[1], '', this.weights.w22, showInToHid);

        // Edges: Hidden to Output
        drawEdge(xPos[1], yPosHid[0], xPos[2], yPosOut[0], '', this.weights.v1, showHidToOut);
        drawEdge(xPos[1], yPosHid[1], xPos[2], yPosOut[0], '', this.weights.v2, showHidToOut);

        // Draw Nodes
        const drawNode = (x, y, label, sublabel, color) => {
            ctx.beginPath();
            ctx.arc(x, y, nodeRadius, 0, Math.PI * 2);
            ctx.fillStyle = color;
            ctx.fill();
            ctx.strokeStyle = '#1e293b';
            ctx.lineWidth = 2;
            ctx.stroke();

            ctx.fillStyle = '#ffffff';
            ctx.textAlign = 'center';
            ctx.font = '14px Arial';
            ctx.fillText(label, x, y + 5);

            ctx.fillStyle = '#334155';
            ctx.font = '12px Arial';
            ctx.fillText(sublabel, x, y + nodeRadius + 15);
        };

        // Inputs
        drawNode(xPos[0], yPosIn[0], 'x1', inputs.x1.toString(), '#64748b');
        drawNode(xPos[0], yPosIn[1], 'x2', inputs.x2.toString(), '#64748b');

        // Hidden
        drawNode(xPos[1], yPosHid[0], 'H1', stepIndex >= 2 ? calc.h1.toFixed(3) : '?', '#3b82f6');
        drawNode(xPos[1], yPosHid[1], 'H2', stepIndex >= 2 ? calc.h2.toFixed(3) : '?', '#3b82f6');

        // Output
        drawNode(xPos[2], yPosOut[0], 'Out', stepIndex >= 3 ? calc.out.toFixed(3) : '?', '#ef4444');

        // Gradients visualization
        if (showBackOut) {
            ctx.fillStyle = '#ef4444';
            ctx.font = 'bold 12px Arial';
            ctx.fillText('∂E/∂v1: ' + calc.dE_dv1.toFixed(4), xPos[2] - 100, yPosOut[0] - 40);
        }

        if (showBackHid) {
            ctx.fillStyle = '#ef4444';
            ctx.fillText('∂E/∂w11: ' + calc.dE_dw11.toFixed(4), xPos[1] - 100, yPosHid[0] - 40);
        }
    }
}
